const crypto = require('crypto');

function hashPassword(password, salt) {
  return crypto.createHmac('sha256', salt)
    .update(password)
    .digest('base64');
}

function generateSalt() {
  return Math.random().toString(36).substring(2, 10);
}

module.exports = {
  hashPassword: (password) => hashPassword(password, generateSalt()),
  comparePassword: function(storedPassword, providedPassword, salt) {
    return hashPassword(providedPassword, salt) === storedPassword;
  }
};